import numpy as np
from typing import List

class InterestRateSwap:
    def __init__(self, notional: float, fixed_rate: float, payment_times: List[float], is_payer: bool):
        self.notional = notional
        self.fixed_rate = fixed_rate
        self.payment_times = payment_times
        self.is_payer = is_payer

    def fixed_leg_pv(self, discount_factors: np.ndarray) -> float:
        pv = 0.0
        for i in range(1, len(self.payment_times)):
            tau = self.payment_times[i] - self.payment_times[i-1]
            pv += tau * discount_factors[i]
        return self.notional * self.fixed_rate * pv

    def floating_leg_pv(self, discount_factors: np.ndarray, forward_rates: np.ndarray) -> float:
        pv = 0.0
        for i in range(1, len(self.payment_times)):
            tau = self.payment_times[i] - self.payment_times[i-1]
            pv += forward_rates[i-1] * tau * discount_factors[i]
        return self.notional * pv

    def value(self, discount_factors: np.ndarray, forward_rates: np.ndarray) -> float:
        fixed_pv = self.fixed_leg_pv(discount_factors)
        float_pv = self.floating_leg_pv(discount_factors, forward_rates)
        if self.is_payer:
            return float_pv - fixed_pv
        return fixed_pv - float_pv

    def par_rate(self, discount_factors: np.ndarray) -> float:
        annuity = 0.0
        for i in range(1, len(self.payment_times)):
            tau = self.payment_times[i] - self.payment_times[i-1]
            annuity += tau * discount_factors[i]
        return (1 - discount_factors[-1]) / annuity

import numpy as np
from scipy.stats import norm

class Caplet:
    def __init__(self, notional: float, strike: float, tau: float):
        self.notional = notional
        self.strike = strike
        self.tau = tau

    def black_price(self, forward_rate: float, volatility: float, time_to_expiry: float, discount_factor: float) -> float:
        if time_to_expiry <= 0:
            return max(0, forward_rate - self.strike) * self.tau * self.notional * discount_factor
        d1 = (np.log(forward_rate/self.strike) + 0.5*volatility**2*time_to_expiry) / (volatility*np.sqrt(time_to_expiry))
        d2 = d1 - volatility*np.sqrt(time_to_expiry)
        return discount_factor * self.notional * self.tau * (forward_rate*norm.cdf(d1) - self.strike*norm.cdf(d2))

