import numpy as np

class VasicekModel:
    def __init__(self, a: float, b: float, sigma: float):
        self.a = a
        self.b = b
        self.sigma = sigma

    def simulate(self, r0: float, T: float, steps: int, paths: int) -> np.ndarray:
        dt = T / steps
        rates = np.zeros((paths, steps+1))
        rates[:,0] = r0
        for i in range(steps):
            dW = np.random.standard_normal(paths) * np.sqrt(dt)
            rates[:,i+1] = rates[:,i] + self.a*(self.b - rates[:,i])*dt + self.sigma*dW
        return rates

    def expected_rate(self, r0: float, t: float) -> float:
        return self.b + (r0 - self.b) * np.exp(-self.a * t)

    def zero_bond_price(self, r: float, T: float) -> float:
        B = (1 - np.exp(-self.a*T)) / self.a
        A = np.exp((self.b - self.sigma**2/(2*self.a**2))*(B-T) - self.sigma**2*B**2/(4*self.a))
        return A * np.exp(-B * r)

import numpy as np
from scipy.stats import norm

class Swaption:
    def __init__(self, notional: float, strike: float, is_payer: bool):
        self.notional = notional
        self.strike = strike
        self.is_payer = is_payer

    def black_price(self, forward_swap_rate: float, volatility: float, time_to_expiry: float, annuity: float) -> float:
        if time_to_expiry <= 0:
            if self.is_payer:
                return max(0, forward_swap_rate - self.strike) * annuity * self.notional
            return max(0, self.strike - forward_swap_rate) * annuity * self.notional
        d1 = (np.log(forward_swap_rate/self.strike) + 0.5*volatility**2*time_to_expiry) / (volatility*np.sqrt(time_to_expiry))
        d2 = d1 - volatility*np.sqrt(time_to_expiry)
        if self.is_payer:
            return annuity * self.notional * (forward_swap_rate*norm.cdf(d1) - self.strike*norm.cdf(d2))
        return annuity * self.notional * (self.strike*norm.cdf(-d2) - forward_swap_rate*norm.cdf(-d1))
